// Cloudflare Worker — Meditación de Luz Crística Landing Page
// Para deployar: CLOUDFLARE_API_TOKEN=<token> npx wrangler deploy

import html from './index.html';

const OG_IMAGE_B64 = "";

const IMG1_B64 = "";

const IMG2_B64 = "";

function base64ToArrayBuffer(base64) {
  const binary = atob(base64);
  const bytes = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) {
    bytes[i] = binary.charCodeAt(i);
  }
  return bytes.buffer;
}

export default {
  async fetch(request) {
    const url = new URL(request.url);

    if (url.pathname === '/og-image.png') {
      const imageBuffer = base64ToArrayBuffer(OG_IMAGE_B64);
      return new Response(imageBuffer, {
        headers: {
          'Content-Type': 'image/jpeg',
          'Cache-Control': 'public, max-age=86400',
        },
      });
    }

    if (url.pathname === '/img/meditacion-lago.jpg') {
      const imageBuffer = base64ToArrayBuffer(IMG1_B64);
      return new Response(imageBuffer, {
        headers: {
          'Content-Type': 'image/jpeg',
          'Cache-Control': 'public, max-age=86400',
        },
      });
    }

    if (url.pathname === '/img/circulo-sanacion.jpg') {
      const imageBuffer = base64ToArrayBuffer(IMG2_B64);
      return new Response(imageBuffer, {
        headers: {
          'Content-Type': 'image/jpeg',
          'Cache-Control': 'public, max-age=86400',
        },
      });
    }

    return new Response(html, {
      headers: {
        'Content-Type': 'text/html;charset=UTF-8',
        'Cache-Control': 'public, max-age=60',
      },
    });
  },
};
